import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	it("dependentRequired and dependencies", () => {
		const dependentRequired = jsonSchemaToType({
			dependentRequired: { credit_card: ["billing_address"] }
		})
		attest(dependentRequired.allows({})).equals(true)
		attest(dependentRequired.allows({ credit_card: "123" })).equals(false)
		attest(
			dependentRequired.allows({ credit_card: "123", billing_address: "x" })
		).equals(true)

		const dependencies = jsonSchemaToType({
			dependencies: { a: ["b"] }
		})
		attest(dependencies.allows({ a: true })).equals(false)
		attest(dependencies.allows({ a: true, b: true })).equals(true)
	})

	it("dependentSchemas", () => {
		const t = jsonSchemaToType({
			dependentSchemas: {
				credit_card: {
					properties: { billing_address: { type: "string" } },
					required: ["billing_address"]
				}
			}
		})
		attest(t.allows({})).equals(true)
		attest(t.allows({ credit_card: "123" })).equals(false)
		attest(t.allows({ credit_card: "123", billing_address: "x" })).equals(true)
	})

	it("local refs, recursive refs, and refs in anyOf", () => {
		const t = jsonSchemaToType({
			$defs: {
				Tree: {
					properties: {
						value: { type: "number" },
						children: { type: "array", items: { $ref: "#/$defs/Tree" } }
					},
					required: ["value"]
				},
				Leaf: { type: "string" }
			},
			anyOf: [{ $ref: "#/$defs/Tree" }, { $ref: "#/$defs/Leaf" }]
		})
		attest(t.allows("leaf")).equals(true)
		attest(t.allows({ value: 1, children: [{ value: 2 }] })).equals(true)
		attest(t.allows({ value: "bad" })).equals(false)
		attest(() =>
			jsonSchemaToType({ $ref: "#/definitions/Tree" } as never)
		).throws(
			"ParseError: Only local $ref values of the form #/$defs/<name> are supported"
		)
		attest(() =>
			jsonSchemaToType({ $ref: "#/$defs/NonExistentDef" } as never)
		).throws(
			'ParseError: Unable to resolve $ref "#/$defs/NonExistentDef" from root $defs'
		)
	})

	it("deep enum equality", () => {
		const t = jsonSchemaToType({ enum: [{ a: [1, 2] }, ["x", { y: true }]] })
		attest(t.allows({ a: [1, 2] })).equals(true)
		attest(t.allows({ a: [2, 1] })).equals(false)
		attest(t.allows(["x", { y: true }])).equals(true)
	})

	it("if/then/else", () => {
		const t = jsonSchemaToType({
			if: { properties: { kind: { const: "card" } }, required: ["kind"] },
			then: { properties: { card: { type: "string" } }, required: ["card"] },
			else: { properties: { cash: { type: "number" } }, required: ["cash"] }
		})
		attest(t.allows({ kind: "card", card: "123" })).equals(true)
		attest(t.allows({ kind: "card" })).equals(false)
		attest(t.allows({ kind: "cash", cash: 1 })).equals(true)
		attest(t.allows({ kind: "cash" })).equals(false)
		attest(
			jsonSchemaToType({ if: false, then: false, else: true }).allows(
				"anything"
			)
		).equals(true)
		attest(jsonSchemaToType({ then: false }).allows("anything")).equals(true)
	})
})

